// ─── Hero Slideshow ───────────────────────────────────────────────────────────
const SLIDES = [
  { img: "data:image/jpeg;base64," },
  { img: "data:image/jpeg;base64," },
  { img: "data:image/jpeg;base64," },
];

function HeroSection({ setPage }) {
  const [slide, setSlide] = useState(0);
  useEffect(() => {
    const iv = setInterval(() => setSlide(s => (s + 1) % 3), 5000);
    return () => clearInterval(iv);
  }, []);
  return (
    <div style={{ position: "relative", minHeight: 560, overflow: "hidden", display: "flex", alignItems: "center" }}>
      {SLIDES.map((s, i) => (
        <div key={i} style={{
          position: "absolute", inset: 0, backgroundImage: `url(${s.img})`, backgroundSize: "cover", backgroundPosition: "center",
          opacity: slide === i ? 1 : 0, transition: "opacity 1.2s ease-in-out",
        }} />
      ))}
      <div style={{ position: "absolute", inset: 0, background: "linear-gradient(160deg,rgba(20,50,30,.38) 0%,rgba(30,80,45,.22) 100%)" }} />
      <div style={{ position: "relative", zIndex: 2, padding: "80px 32px", color: "#fff", maxWidth: 700 }}>
        <h1 style={{ fontSize: "clamp(1.8rem,4vw,3rem)", fontWeight: 800, marginBottom: 16, textShadow: "0 2px 10px rgba(0,0,0,.55)", lineHeight: 1.2 }}>
          Smart Waste Management<br />for Bengaluru
        </h1>
        <p style={{ fontSize: "1.15rem", marginBottom: 28, textShadow: "0 1px 8px rgba(0,0,0,.5)", opacity: .95 }}>
          Join thousands of citizens keeping our city clean.<br />Report, track, and help optimize waste collection.
        </p>
        <div style={{ display: "flex", gap: 16, flexWrap: "wrap" }}>
          <button onClick={() => setPage("report")} style={btnStyle("primary")}>📷 Report Waste</button>
          <button onClick={() => setPage("admin")} style={btnStyle("secondary")}>🔒 Admin Portal</button>
        </div>
      </div>
      <div style={{ position: "absolute", bottom: 18, left: "50%", transform: "translateX(-50%)", display: "flex", gap: 10, zIndex: 3 }}>
        {SLIDES.map((_, i) => (
          <button key={i} onClick={() => setSlide(i)} style={{
            width: 10, height: 10, borderRadius: "50%", border: "2px solid rgba(255,255,255,.4)",
            background: slide === i ? C.primaryLight : "rgba(255,255,255,.55)",
            cursor: "pointer", transform: slide === i ? "scale(1.35)" : "scale(1)", transition: "all .3s",
          }} />
        ))}
      </div>
    </div>
  );
}

function btnStyle(type) {
  if (type === "primary") return {
    padding: "14px 28px", border: "none", borderRadius: 8, fontSize: "1rem", fontWeight: 600,
    cursor: "pointer", background: `linear-gradient(135deg,${C.primary},${C.primaryDark})`,
    color: "#fff", transition: "all .3s",
  };
  return {
    padding: "12px 24px", border: "2px solid rgba(255,255,255,.7)", borderRadius: 8,
    fontSize: "1rem", fontWeight: 600, cursor: "pointer",
    background: "rgba(255,255,255,.18)", color: "#fff", backdropFilter: "blur(4px)", transition: "all .3s",
  };
}

